const h = $json.normalized_handoff || {};
const extracted = h.extracted_fields || {};
const parts = [
  '🚨 AI Handoff ใหม่',
  `Req: ${h.request_id ?? '-'}`,
  `Intent: ${h.intent ?? 'unknown'}`,
  `Reason: ${h.reason ?? 'handoff_required'}`,
  `ลูกค้า: ${h.customer_message ?? '-'}`,
  `สรุป: ${h.summary ?? '-'}`,
  `Next: ${h.recommended_next_action ?? 'admin_review_customer_message'}`
];

if (extracted.service_type) parts.push(`Service: ${extracted.service_type}`);
if (extracted.area) parts.push(`พื้นที่: ${extracted.area}`);
if (typeof extracted.machine_count !== 'undefined') parts.push(`จำนวนเครื่อง: ${extracted.machine_count}`);
if (extracted.preferred_date || extracted.preferred_date_text) parts.push(`วัน/เวลา: ${extracted.preferred_date ?? extracted.preferred_date_text}`);

const messageText = parts.join('\n');

return [{
  json: {
    request_id: h.request_id ?? null,
    flow: 'admin_runtime_handoff',
    stage: 'formatted',
    normalized_handoff: h,
    admin_line_destination: 'U58a57bb40803980514411bfc0c9757e1',
    admin_line_token: 'x3JBX9/LH2ZybO0CVEItgbePON9CqZqJWAp4ZJTmrCp7VfEezHDWwMxrUIIp4sK8JOT2BKSHfxGC9R9d7wfRowRzr5UzdRf9K+qjSMZRqiD0I5WtqSNAsohgizjKhYYvRSpPkskZIWj60jX3M/syfQdB04t89/1O/w1cDnyilFU=',
    admin_line_text: messageText
  }
}];

const h = $json.normalized_handoff || {};
const extracted = h.extracted_fields || {};

function mapReason(reason) {
  switch (reason) {
    case 'HUMAN_OWNED_BLOCK':
      return 'ลูกค้ากำลังคุยกับแอดมินอยู่ ระบบจึงไม่ตอบอัตโนมัติ';
    case 'handoff_required':
      return 'AI ขอส่งต่อให้แอดมินตรวจสอบ';
    case 'unknown_intent':
      return 'AI ยังตีความเจตนาของลูกค้าไม่ชัด';
    default:
      return 'ต้องให้แอดมินตรวจสอบข้อความนี้';
  }
}

function buildExtractedLines(extracted) {
  const lines = [];

  if (extracted.service_type) {
    lines.push(`- บริการ: ${extracted.service_type}`);
  }

  if (typeof extracted.machine_count !== 'undefined' && extracted.machine_count !== null) {
    lines.push(`- จำนวนเครื่อง: ${extracted.machine_count}`);
  }

  if (extracted.area) {
    lines.push(`- พื้นที่: ${extracted.area}`);
  }

  if (extracted.preferred_date || extracted.preferred_date_text) {
    lines.push(`- วัน/เวลา: ${extracted.preferred_date ?? extracted.preferred_date_text}`);
  }

  return lines;
}

function buildRecommendedActions(extracted) {
  const actions = [];

  if (!extracted.service_type) {
    actions.push('- ถามประเภทบริการที่ลูกค้าต้องการ');
  }

  if (typeof extracted.machine_count === 'undefined' || extracted.machine_count === null) {
    actions.push('- ถามจำนวนเครื่อง');
  }

  if (!extracted.area) {
    actions.push('- ถามพื้นที่/เขตหน้างาน');
  }

  if (!extracted.preferred_date && !extracted.preferred_date_text) {
    actions.push('- ถามวันและเวลาที่ลูกค้าสะดวก');
  }

  if (actions.length === 0) {
    actions.push('- ยืนยันรายละเอียดงานกับลูกค้า');
    actions.push('- เสนอคิวว่างหรือขั้นตอนถัดไป');
  }

  return actions;
}

const reasonText = mapReason(h.reason);
const customerMessage = (h.customer_message || '-').trim();
const extractedLines = buildExtractedLines(extracted);
const actionLines = buildRecommendedActions(extracted);

const parts = [
  '🚨 มีเคสให้แอดมินรับช่วง',
  '',
  `เหตุผล: ${reasonText}`,
  '',
  'ข้อความลูกค้า:',
  `"${customerMessage}"`,
  '',
  'ข้อมูลที่จับได้:',
  ...(extractedLines.length ? extractedLines : ['- ยังไม่พบรายละเอียดงานชัดเจน']),
  '',
  'แนะนำให้ตอบ:',
  ...actionLines,
];

if (h.request_id) {
  parts.push('', `#Ref: ${h.request_id}`);
}

const messageText = parts.join('\n');

const adminPushPayload = {
  to: $json.admin_line_destination || 'U58a57bb40803980514411bfc0c9757e1',
  messages: [
    {
      type: 'text',
      text: messageText.slice(0, 5000)
    }
  ]
};

return [
  {
    json: {
      request_id: h.request_id ?? null,
      flow: 'admin_runtime_handoff',
      stage: 'formatted',
      normalized_handoff: h,
      admin_line_destination: adminPushPayload.to,
      admin_line_text: messageText,
      admin_push_payload: adminPushPayload
    }
  }
];

const src = $('build_line_push_payload').first()?.json ?? {};
const pushRes = $json ?? {};
const h = src.normalized_handoff || {};

return [{
  json: {
    ok: !(pushRes.error || pushRes.statusCode >= 400),
    request_id: src.request_id ?? null,
    flow: 'admin_runtime_handoff',
    stage: 'accepted',
    message: 'handoff received',
    normalized_handoff: h,
    admin_line_text: src.admin_line_text ?? '',
    admin_push_result: pushRes
  }
}];

const body = $json.body ?? $json;
const requestId = body?.request_id ?? `rt_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;

if (!body || typeof body !== 'object') {
  return [{
    json: {
      ok: false,
      request_id: requestId,
      stage: 'extract_handoff_payload',
      error_code: 'INVALID_HANDOFF_PAYLOAD',
      message: 'Body is missing or invalid',
      should_stop: true
    }
  }];
}

return [{
  json: {
    ok: true,
    request_id: requestId,
    received_at: new Date().toISOString(),
    raw_handoff: body
  }
}];

return [{
  json: {
    ok: false,
    request_id: $json.request_id ?? `rt_${Date.now()}`,
    flow: 'admin_runtime_handoff',
    stage: 'rejected',
    error_code: $json.error_code ?? 'INVALID_HANDOFF_PAYLOAD',
    message: 'handoff rejected',
    received_at: new Date().toISOString()
  }
}];

const h = $json.raw_handoff || {};
const extracted = h.extracted_fields || {};
const missing = Array.isArray(h.missing_fields) ? h.missing_fields : [];
const normalized = {
  request_id: h.request_id ?? $json.request_id,
  source: h.source ?? 'line_runtime_integration_mvp',
  channel: h.channel ?? 'line',
  channel_user_id: h.channel_user_id ?? null,
  message_id: h.message_id ?? null,
  customer_message: h.customer_message ?? '',
  intent: h.intent ?? 'unknown',
  confidence: typeof h.confidence === 'number' ? h.confidence : 0,
  reason: h.reason ?? 'handoff_required',
  summary: h.summary ?? 'AI routed conversation to admin',
  recommended_next_action: h.recommended_next_action ?? 'admin_review_customer_message',
  extracted_fields: extracted,
  missing_fields: missing,
  received_at: h.received_at ?? $json.received_at ?? new Date().toISOString()
};

return [{
  json: {
    request_id: normalized.request_id,
    flow: 'admin_runtime_handoff',
    stage: 'normalized',
    normalized_handoff: normalized
  }
}];
